Gist連結
Define Variables Python a = 1 b = 0.0 c = &#39;xxx&#39; C++ int a = 1; auto a = 1; double b = 0.0; auto b = 0.0; const char c[] = &#34;xxx&#34;; // C string (char array) const char* c = &#34;xxx&#34;; // C string (pointer) std::string c = &#34;xxx&#34;; std::string c(&#34;xxx&#34;); std::string c{&#34;xxx&#34;}; Variable Scopes Python global_var1 = 1 def func(arg): local_var = 2 global global_var2 global_var2 = &#39;xxx&#39; # global if arg: local_var2 = 0.5 # scope: function ... # if arg evaluates to True, # local_var2 is still accessible here. return False C++ int global_var1 = 1; // global static std::string global_var2; // global in the current file bool func(bool arg){ int local_var = 2; global_var2 = &#34;xxx&#34;; if(arg){ double local_var2 = 0.5; // scope: if block ....} // local_var2 is undefined here} Reference Python s1 = {&#34;key1&#34; : 100} s2 = s1 # reference the same object s2[&#34;key2&#34;] = 200 print(s1[&#34;key1&#34;]) # {&#34;key1&#34;:100, &#34;key2&#34;: 200} s2 = {} # s1 is NOT changed, s1 and s2 # reference different objects now C++ std::unordered_map&lt;std::string, int&gt; s1 = {&#34;key1&#34; : 100}; std::unordered_map&lt;std::string, int&gt; s2 = s1; // copy the whole object std::unordered_map&lt;std::string, int&gt;&amp; s2 = s1; // reference the same object s2 = std::unordered_map&lt;std::string, int&gt;(); // s1 is changed, s1 and s2 still reference the same object // C++ 11 auto s2 = s1; // copy the whole object (slow) auto&amp; s2 = s1; // reference the same object // Now s2 is a reference to s1 auto s3 = s2; // copy the whole s1 object. s3 is NOT a reference const auto&amp; s3 = s2; // reference the same s1 object Conditional Python if a == 1 and b == 2: pass elif c == 3 or d == 4: pass else: pass if a == 1: ... elif a == 2: ... elif a == 3: ... else: ... C++ if (a == 1 &amp;&amp; b == 2){} else if(c == 3 || d == 4){} else {} switch(a){ case 1: ... break; // without break, will run case 2 as well case 2: { // create a new scope if we need to define new variables int a = 100; break;} default: // it&#39;s good practice to always add this ...};
Namespace &amp; Imports Python # Import: File: app/bidders/ai_util.py import app.bidders.ai_util # Namespace: defined by directory structure # Fully qualified names: app.bidders.ai_util.func(&#34;xxx&#34;) C++ // Import: Files: app/bidders/ai_util.hpp &amp; ai_util.cpp #include &#34;app/bidders/ai_utils.hpp&#34; // Namespace: not related to directory structure namespace app { namespace bidder { namespace ai_util { void func(const char* str); } } } // Fully qualified names: app::bidders::ai_util::func(&#34;xxx&#34;); Loops Python for i in range(100): pass while cond: ... a = [0, 1, 100] for item in a: pass b = {&#34;key&#34;: 0.5, &#34;key2&#34;, 1.0} for key, val in b.iteritems(): pass C++ for(int i = 0; i &lt; 100; ++i){...} while(cond){} std::vector&lt;int&gt; a = {0, 1, 100}; for(auto&amp; item: a){ // without &amp;, this will copy each item } std::unordered_map&lt;std::string, double&gt; b = {{&#34;key&#34;, 0.5}, {&#34;key2&#34;, 1.0}}; for(auto&amp; item: b){ // without &amp;, this will copy each item auto&amp; key = item.first; auto&amp; val = item.second;} Functions Python def func(arg1, arg2): .... return ret1, ret2, ret3 C++ void func(const Arg1&amp; arg1, const Arg2&amp; arg2, Ret1&amp; ret1, Ret2&amp; ret2, Ret3&amp; ret3 ){... ret1 = ....; ret2 = ....; ret3 = ....;} No multiple return values Need to specify the type of the return value Every variable needs to have type declaration Declaration before use is required Add const to the references that are not changed by the method Declare in *.hpp, implement in *.cpp (for public functions) Class Definition Python # Python version: only one *.py file: class PythonClass(ParentClass): def __init__(self): # constructor, pass instance as self ParentClass.__init__(self) # python2 self.attrib = 1111 Self.attrib2 = &#39;xxx&#39; def some_method(self, arg1, arg2): return arg1 * arg2 + self.attrib def _some_private_method(self): # kind of private func pass C++ // --------- Declaration: cpp_class.hpp --------- class CppClass: public ParentClass { public: CppClass(): ParentClass(), attrib(5566), attrib2(&#34;xxx&#34;){} virtual ~CppClass(): { // destructor: free allocated resources here} double someMethod(double arg1, double arg2); private: void somePrivateMethod(){} int attrib; std::string attrib2;}; // --------- Implementation: cpp_class.cpp --------- #include &#34;cpp_class.hpp&#34; double CppClass::someMethod(double arg1, double arg2){ return arg1 * arg2 + attrib;} Virtual function Python class Raccoon: def get_name(self): return &#34;raccoon&#34; class Zebra(Raccoon): def get_name(self): return &#34;zebra_&#34; + Raccoon.get_name() def func(maybe_racoon): print(maybe_racoon.get_name()) obj = Zebra() func(obj) # pintout: zebra_raccoon C++ class Raccoon { public: std::string getName() const { return &#34;raccoon&#34;;}}; class Zebra: public Raccoon { public: std::string getName() const { return &#34;zebra&#34; + Raccoon::getName();}}; void func(const Raccoon&amp; maybeRaccoon){ std::cout &lt;&lt; maybeRaccoon.getName() &lt;&lt; std::endl;} Zebra obj; func(obj); // pintout: raccoon C++ class Raccoon { public: virtual std::string getName() const { return &#34;raccoon&#34;;}}; class Zebra: public Raccoon { public: std::string getName() override const { return &#34;zebra&#34; + Raccoon::getName();}}; void func(const Raccoon&amp; maybeRaccoon){ std::cout &lt;&lt; maybeRaccoon.getName() &lt;&lt; std::endl;} Zebra obj; func(obj); // pintout: zebra_raccoon Manage Objects Python obj = ObjClass() obj.method(arg) obj.attribute = 100 obj2 = obj # reference the same object # Manual delete is not needed C++ ObjClass* obj = nullptr; // prefer nullptr over NULL ObjClass* obj = new ObjClass(); // allocate on heap obj-&gt;method(arg); obj-&gt;attribuge = 100; auto obj2 = obj; // point to the same object auto obj2 = *obj; // copy! auto&amp; obj2 = *obj; // reference the same object delete obj; // when not used, manual delete is required ObjectClass localObj(); // allocate on local stack localObj.method(arg); // Raw pointer is not recommended. Use smart pointers #include &lt;memory&gt; std::shared_ptr&lt;ObjClass&gt; obj; auto obj = std::make_shared&lt;ObjClass&gt;(); obj-&gt;method(arg); obj-&gt;attribute = 100; // manual delete is not needed auto obj2 = obj; // point to the same object (no * or &amp;) Common Data Types (Python -&gt; C++) int: int, long, unsigned int, unsigned long (size is architecture dependent) std::int64_t, std::uint64_t, std::int16_t, &hellip; (#include , well-defined sizes) bool:bool float: double (64-bit), float(32-bit, bad performance &amp; not recommended) str, bytes: std::string (#include ) containers: list: std::vector&lt;&gt; (#include ) dict: std::unordered_map&lt;&gt; (#include &lt;unordered_map&gt;) set: std::unordered_set&lt;&gt; (#include &lt;unordered_set&gt;) None: For float, can use NAN (#include ) and use std::isnan(number) to check if it’s NAN For string, just use empty string and use str.empty() to check if it’s empty Define Strings Python s = &#34;this is a string&#34; s2 = s # s2 and s reference the same object len(s) t = &#34;prefix_&#34; + s + &#34;_suffix&#34; t = &#34;prefix1&#34; + &#34;prefix2&#34; + s s = &#34;has\0zero&#34; # len(s): 8 C++ #include &lt;string&gt; std::string s = &#34;this is a string&#34;; auto s2 = s; // copy s to s2 (new object) auto&amp; s2 = s; // s2 is a reference only s.length(); auto t = &#34;prefix_&#34; + s + &#34;_suffix&#34;; // works but slower std::string t = &#34;prefix_&#34;; t += s; t += &#34;_suffix&#34;; // good auto t = &#34;prefix1&#34; + &#34;prefix2&#34; + s; // does not work std::string s = &#34;has\0zero&#34;; // incorrect s.length(): 3 std::string s(&#34;has\0zero&#34;, 8); // correct Alternative (C++ 14): using namespace std::string_literals; auto z = &#34;has\0zero&#34;s; // add &#34;s&#34; suffix, z is std::string auto z = &#34;has\0zero&#34;; // z is char* pointer String Methods Python t = &#34;test str&#34; if t.find(&#34;sub_str&#34;) == -1: print(&#34;not found&#34;) u = t[1:2] # get sub string u = t[2:] # get sub string til end if not t: print(&#34;empty str&#34;) v = t.lower() C++ #include &lt;string&gt; std::string t = &#34;test str&#34;; if (t.find(&#34;sub_str&#34;) == std::string::npos) std::cout &lt;&lt; &#34;not found\n&#34;; if(t.empty()) std::cout &lt;&lt; &#34;empty str\n&#34;; auto u = t.substr(1, 2); auto u = t.substr(1); #include &lt;algorithm&gt; #include &lt;cctype&gt; std::transform(t.begin(), t.end(), t.begin(), std::tolower); // This does not work in unicode List (dynamic array) Python a = [1, 2, 3] b = [&#34;str1&#34;, &#34;str2&#34;, &#34;str3&#34;] c = [&#34;xxx&#34;, {}, 100, 0.5] # cannot be done in C++ a.append(100) a.insert(2, 10) del a[1], a[0:2] tmp = a[0:2] tmp = a[2] tmp2 = b[1] # reference the element C++ #include &lt;vector&gt; std::vector&lt;int&gt; a = {1, 2, 3}; std::vector&lt;std::string&gt; b = {&#34;str1&#34;, &#34;str2&#34;, &#34;str3&#34;}; std::vector&lt;????&gt; c // cannot be done in C++ a.push_back(100); a.insert(a.begin() + 2, 10); a.erase(a.begin() + 1); a.erase(a.begin(), a.begin() + 2); std::vector&lt;int&gt; tmp{a.begin(), a.begin() + 2}; auto tmp = a[2]; auto tmp2 = b[1]; // copy the element! auto&amp; tmp2 = b[1]; // reference the element s Set Python a = set() a = {&#34;1&#34;, &#34;2&#34;, &#34;3&#34;} b = [1, 2, 3] c = set(b) a.add(&#34;x&#34;) a.remove(&#34;2&#34;) if &#34;4&#34; in a: pass C++ #include &lt;unordered_set&gt; std::unordered_set&lt;std::string&gt; a; std::unordered_set&lt;std::string&gt; a = {&#34;1&#34;, &#34;2&#34;, &#34;3&#34;}; std::vector&lt;int&gt; b = {1, 2, 3}; std::unordered_set&lt;int&gt; c(b.begin(), b.end()); a.insert(&#34;x&#34;); a.erase(&#34;2&#34;); if (a.find(&#34;4&#34;) != a.end()){ ...} Dict Python d = {&#34;a&#34;: 1, &#34;b&#34;: 2} nested = { &#34;a&#34;: {&#34;a1&#34;: 0.5}, &#34;b&#34;: {&#34;b1&#34;: 0.3, &#34;b2&#34;: 0.4},} free = {&#34;a&#34;: 100, &#34;b&#34;: &#34;xxx&#34;, 50: None} # cannot do this in C++ d = defaultdict(lambda: &#34;null&#34;); # cannot easily do this in C++ C++ #include &lt;unordered_map&gt; std::unordered_map&lt;std::string, int&gt; d = { {&#34;a&#34;, 1}, {&#34;b&#34;, 2}}; std::unordered_map&lt;std::string, std::unordered_map&lt;std::string, int&gt;&gt; nested = { {&#34;a&#34;: {{&#34;a1&#34;, 0.5}}}, {&#34;b&#34;: {{&#34;b1&#34;, 0.3}, {&#34;b2&#34;, 0.4}},}; Common Dict Operations Python d[&#34;new_key&#34;] = 100 d[&#34;no such key&#34;] # raise KeyError del d[&#34;key&#34;]; gc.collect() if &#34;key&#34; in d: e = d[&#34;key&#34;] for key, val in d.iteritems(): pass C++ d[&#34;new_key&#34;] = 100; d[&#34;no such key&#34;] // create a new item for it d.erase(&#34;key&#34;); auto iter = d.find(&#34;key&#34;); if(iter != d.end()){ // without &amp;, this will do copy auto&amp; e = iter-&gt;second;} // C++ 11 ranged for loop syntax for(auto&amp; item: d){ // without &amp;, this will do copy auto&amp; key = item.first; auto&amp; val = item.second; ...}
